  { id: 'Nissan Leaf', brand: 'Transit left truck', badge: 'Overdue', bg: 'bg-rose-100', text: 'text-rose-700', dot: 'bg-rose-500', time: '35 minutes ago', loc: 'Sentilrent', subloc: 'Check Room Issue' },
