const INSPECTIONS_DATA = [
  { vehicle: 'Ford Transit', tag: 'A-283', type: 'Transit light truck', due: 'Last Active', status: 'Overdue', stBg: 'bg-rose-100', stText: 'text-rose-700', sects: '10/140', driver: 'Adam Leaf', dept: 'East Tree 1', dueLabel: 'Due 30m Late' },
  { vehicle: 'Toyota Hilux', tag: 'A-283', type: 'Toyota Hilux', due: 'Last Active', status: 'Overdue', stBg: 'bg-rose-100', stText: 'text-rose-700', sects: '87/3490', driver: 'Benit Runalt', dept: 'East Battalion', dueLabel: 'Due 33m Late' },
  { vehicle: 'Nissan Leaf', tag: 'Don\'t left truck', type: '', due: 'Last Active', status: 'Seat', stBg: 'bg-blue-100', stText: 'text-blue-700', sects: '91_K08', driver: 'Alice Meriver', dept: 'East Inspection', dueLabel: 'Due 40m Late' },
