const TOP_DRIVERS_1 = [
  { vId: '12:21', vType: '18.007', tDate: 'Finpot Both', status: 'Due Date', subStatus: '00:04:470', label: 'Overdue', stBg: 'bg-blue-100 text-blue-700' },
  { vId: '25:31', vType: '18.048', tDate: 'Safety Service', status: 'Due Date', subStatus: '00:04:470', label: 'Overdue', stBg: 'bg-rose-100 text-rose-700' },
  { vId: '20:21', vType: '18.002', tDate: 'Denins Articles', status: 'Due Date', subStatus: '00:04:470', label: 'Overdue', stBg: 'bg-blue-100 text-blue-700' },
  { vId: '20:01', vType: '18.003', tDate: 'Safety Service', status: 'Due Date', subStatus: '00:04:470', label: 'Overdue', stBg: 'bg-blue-100 text-blue-700' },
  { vId: '20:01', vType: '18.012', tDate: 'Safety Service', status: 'Due Date', subStatus: '00:04:470', label: 'Overdue', stBg: 'bg-blue-100 text-blue-700' },
];

const TOP_DRIVERS_2 = [
  { name: 'Adam Smith', loc: 'East Region', dist: '8,322 km', score: '97%', cnt: 1 },
  { name: 'Emma Brown', loc: 'East Region', dist: '7,002 km', score: '97%', cnt: 2 },
  { name: 'John Davis', loc: 'East Region', dist: '5,525 km', score: '97%', cnt: 4.1 },
  { name: 'Sarah Maison', loc: 'East Region', dist: '4,335 km', score: '97%', cnt: 4.1 },
  { name: 'Keive Last', loc: 'East Region', dist: '5,528 km', score: '97%', cnt: 4.1 },
];

const DOWNTIME_DATA = [
  { name: '1', val: 50 }, { name: '2', val: 70 }, { name: '3', val: 68 },
  { name: '4', val: 55 }, { name: '5', val: 65 }, { name: '6', val: 40 },
  { name: '7', val: 45 }, { name: '8', val: 75 }, { name: '9', val: 80 }, { name: '10', val: 55 },
  { name: '11', val: 50 }, { name: '12', val: 70 }, { name: '13', val: 68 },
];

const FLEET_COMP_DATA = [
  { name: 'Light Duty:', val1: 38, var: 10 },
  { name: 'Medium Duty:', val1: 40, var: 20 },
  { name: 'Heavy Duty:', val1: 50, var: 18 },
  { name: 'Electric:', val1: 18, var: 30 },
  { name: 'Other:', val1: 14, var: 20 },
];

/* ─── REUSABLE COMPONENTS ─── */
function DashboardTabs({ tabs, activeTab, onTabSelect }: { tabs: string[], activeTab: string, onTabSelect: (t: string) => void }) {
  return (
    <div className="flex bg-slate-100/80 p-1 rounded-md max-w-fit shadow-inner">
      {tabs.map(t => (
        <button
          key={t}
          onClick={() => onTabSelect(t)}
          className={cn(
            "px-4 py-1.5 text-sm font-medium rounded-sm transition-all duration-200",
            activeTab === t ? "bg-blue-600 text-white shadow-sm" : "text-slate-500 hover:text-slate-800"
          )}
        >
          {t}
        </button>
      ))}
    </div>
  );
}

function KpiCard({ data }: { data: any }) {
  const Icon = data.icon;
  return (
    <div className="bg-white rounded-xl p-4 shadow-[0_2px_8px_-2px_rgba(0,0,0,0.05)] border border-slate-100/50 flex flex-col justify-between">
      <div className="flex items-center justify-between mb-2">
        <div className="flex items-center gap-1.5">
          <span className="text-xs font-semibold text-slate-500 uppercase tracking-wide">{data.label}</span>
          <AlertTriangle className="w-3 h-3 text-slate-300" />
        </div>
      </div>
      <div className="flex items-baseline gap-2 mb-1">
        <h3 className="text-3xl font-bold text-slate-800 tracking-tight">{data.value}</h3>
        {data.badge && (
          <span className={cn("text-xs font-medium", data.badgeColor)}>{data.badge}</span>
        )}
      </div>
      <p className="text-xs text-slate-400 mb-4 h-4">{data.sub}</p>
      <div className="w-full h-1.5 bg-slate-100 rounded-full overflow-hidden">
        <div className={cn("h-full rounded-full", data.barInfo)} style={{ width: `${data.progress}%` }} />
      </div>
    </div>
  );
}

function SectionCard({ title, rightAction, children, className }: { title?: React.ReactNode, rightAction?: React.ReactNode, children: React.ReactNode, className?: string }) {
  return (
    <div className={cn("bg-white rounded-xl shadow-[0_2px_8px_-2px_rgba(0,0,0,0.05)] border border-slate-100/50 overflow-hidden flex flex-col", className)}>
      {(title || rightAction) && (
        <div className="px-5 py-4 flex items-center justify-between border-b border-slate-50/50">
          {typeof title === 'string' ? <h3 className="text-base font-semibold text-slate-800">{title}</h3> : title}
          {rightAction}
        </div>
      )}
      <div className="p-5 flex-1 flex flex-col overflow-hidden min-h-0 min-w-0">
        {children}
      </div>
    </div>
  );
}



/* ─── MAIN PAGE PAGE ─── */
export default function DashboardPage() {
  const [activeTab, setActiveTab] = useState('Overview');
  const [analyticsTab, setAnalyticsTab] = useState('Fleet Analytics');

  return (
    <div className="min-h-full w-full bg-[#f8fafc] flex flex-col min-w-0 text-slate-800 pb-20">
      <div className="px-6 pt-5 pb-6 max-w-[1600px] w-full mx-auto space-y-6">

        {/* 1. TOP TABS / FILTER BAR */}
        <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 w-full">
          <DashboardTabs 
            tabs={['Overview', 'Vehicles', 'Drivers', 'Maintenance']} 
            activeTab={activeTab} 
            onTabSelect={setActiveTab} 
          />
          <div className="relative group min-w-[200px]">
            <button className="w-full flex items-center justify-between px-4 py-2 bg-white border border-slate-200 shadow-sm rounded-md text-sm font-medium text-slate-700 hover:bg-slate-50 transition-colors">
              <span>All Regions</span>
              <ChevronDown className="w-4 h-4 text-slate-400" />
            </button>
          </div>
        </div>

        {/* 2. KPI CARDS */}
        <div className="grid grid-cols-1 md:grid-cols-3 xl:grid-cols-5 gap-4">
          {KPI_METRICS.map(kpi => <KpiCard key={kpi.label} data={kpi} />)}
        </div>

        {/* 3. MAIN CONTENT ROW 1 */}
        <div className="grid grid-cols-1 xl:grid-cols-3 gap-5">
          {/* LEFT: Live Fleet Monitor & Map */}
          <SectionCard className="xl:col-span-2">
            <div className="flex items-center justify-between mb-4">
              <h3 className="text-lg font-semibold text-slate-800">Live Fleet Monitor</h3>
              <div className="flex items-center gap-2">
                <span className="text-sm text-slate-500">Last 30 Days</span>
                <ChevronDown className="w-4 h-4 text-slate-400" />
              </div>
            </div>
            {/* Map Legends */}
            <div className="flex flex-wrap items-center justify-between gap-3 mb-4 bg-slate-50/50 p-2 rounded-lg border border-slate-100">
              <div className="flex items-center gap-4 px-2">
                <div className="flex items-center gap-1.5"><div className="w-2.5 h-2.5 rounded bg-emerald-400" /><span className="text-xs font-medium text-slate-600">Active Vehicles</span></div>
                <div className="flex items-center gap-1.5"><div className="w-2.5 h-2.5 rounded bg-amber-400" /><span className="text-xs font-medium text-slate-600">Maintenance</span></div>
                <div className="flex items-center gap-1.5"><div className="w-2.5 h-2.5 rounded bg-rose-400" /><span className="text-xs font-medium text-slate-600">Alert</span></div>
              </div>
              <button className="px-3 py-1 bg-white border border-slate-200 text-slate-600 text-xs font-medium rounded shadow-sm hover:bg-slate-50 transition-colors">All Group</button>
            </div>

            {/* Map Area */}
            <div className="relative w-full h-[320px] bg-[#eaf2f9] rounded-xl overflow-hidden border border-slate-200/60 shadow-inner">
              {/* Dummy Map Visuals */}
              <svg className="absolute inset-0 w-full h-full opacity-60" preserveAspectRatio="none">
                {/* Organic map paths */}
                <path d="M-10,40 Q50,20 120,60 T250,30 T400,90 L400,400 L-10,400 Z" fill="#d8e5f2" />
                <path d="M150,-10 Q200,50 350,10 T500,60 T700,40 L700,-10 Z" fill="#d8e5f2" />
                <path d="M500,400 Q450,320 600,280 T800,350 L800,400 Z" fill="#d8e5f2" />
                <path d="M650,80 Q700,120 780,100 T900,150 L900,-10 L650,-10 Z" fill="#d8e5f2" />
                {/* Roads */}
                <path d="M0,80 Q150,100 250,50 T450,200 T800,150" fill="none" stroke="#fff" strokeWidth="2" strokeDasharray="5,5" />
                <path d="M200,0 Q250,150 150,250 T300,400" fill="none" stroke="#fff" strokeWidth="3" />
                <path d="M600,0 Q650,200 550,300 T800,400" fill="none" stroke="#fff" strokeWidth="2" />
              </svg>

              {MAP_VEHICLES.map(v => (
                <div key={v.id} className="absolute z-10 hidden sm:flex items-center flex-col transform -translate-x-1/2 -translate-y-1/2 group cursor-pointer" style={{ left: `${v.x}%`, top: `${v.y}%` }}>
                  <div className={cn(
                    "px-2 py-1 rounded-full text-white text-xs font-bold shadow-md",
                    v.status === 'Active Vehicles' ? 'bg-emerald-500' :
                    v.status === 'Maintenance' ? 'bg-amber-500' : 'bg-rose-500'
                  )}>
                    {v.label}
                  </div>
                  <div className={cn(
                    "w-2 h-2 rounded-full mt-1 border-2 border-white shadow-sm",
                    v.status === 'Active Vehicles' ? 'bg-emerald-500' :
                    v.status === 'Maintenance' ? 'bg-amber-500' : 'bg-rose-500'
                  )} />
