                  <div key={v.id} className="grid grid-cols-4 gap-4 px-4 py-3 bg-white hover:bg-slate-50/50 rounded-lg group transition-colors duration-150 items-center border border-transparent hover:border-slate-100">
                    <div className="flex items-center gap-3">
                      <div className="w-8 h-8 rounded-full bg-slate-100 flex items-center justify-center border border-slate-200 flex-shrink-0 relative overflow-hidden">
                        <Car className="w-4 h-4 text-slate-500" />
                      </div>
                      <div>
                        <div className="text-sm font-semibold text-slate-800">{v.id}</div>
                        <div className="text-xs text-slate-500">{v.brand}</div>
                      </div>
                    </div>
                    <div>
                      <span className={cn("inline-flex items-center gap-1.5 px-2 py-0.5 rounded text-xs font-semibold", v.bg, v.text)}>
                        <span className={cn("w-1.5 h-1.5 rounded-full", v.dot)} />
