                </div>
                <div className="flex h-2.5 rounded-full overflow-hidden w-full bg-slate-100">
                  <div className="h-full bg-emerald-500" style={{width: '60%'}}></div>
                  <div className="h-full bg-amber-400" style={{width: '30%'}}></div>
                </div>
              </div>

              <div className="space-y-3">
                {[
                  { label: 'Vehicles with Critical Issues', val: '8%', dot: 'bg-emerald-500', trend: '41%' },
                  { label: 'Vehicles with Dents / Issues', val: '8%', dot: 'bg-rose-500', trend: '0%' },
                  { label: 'Overdue Alerts', val: '5', dot: 'bg-rose-500', trend: '102' },
                  { label: 'Open Service Tasks', val: '7', dot: 'bg-emerald-500', trend: '102' },
                ].map(r => (
                  <div key={r.label} className="flex items-center justify-between py-1 border-b border-slate-50 last:border-0 last:pb-0">
                    <span className="text-sm text-slate-600">{r.label}</span>
                    <div className="flex items-center gap-3">
                      <span className="font-semibold text-slate-800">{r.val}</span>
                      <span className="text-xs text-slate-400 w-6 text-right flex items-center justify-end gap-1">
                        <div className={cn("w-1.5 h-1.5 rounded-full", r.dot)} />
                        {r.trend}
                      </span>
                    </div>
                  </div>
                ))}
                <div className="flex items-center justify-between pt-2 border-t border-slate-100 mt-2">
                  <span className="text-sm font-semibold text-slate-700">Total Defects last 30 days</span>
                  <div className="flex items-center gap-3">
                    <span className="text-lg font-bold text-slate-800">132</span>
                    <span className="text-xs text-slate-400 w-6 text-right text-emerald-500">102</span>
                  </div>
                </div>
              </div>
            </SectionCard>

            <SectionCard title={<div className="flex items-center justify-between w-full">
                <span className="text-lg font-semibold text-slate-800">Upcoming Schedule</span>
                <ChevronDown className="w-4 h-4 text-slate-400"/>
              </div>}>
               <div className="flex justify-between text-xs text-slate-400 uppercase tracking-wide mb-3 px-2">
                 <span>Items &amp; Tags</span>
                 <div className="flex gap-4">
                   <span>Due Days</span>
                   <span>Count</span>
                 </div>
               </div>
               <div className="space-y-1">
                 {UPCOMING_SCHEDULE.map((s,i) => (
                   <div key={s.title} className="flex items-center justify-between py-2 px-3 hover:bg-slate-50 rounded-lg group transition-colors border border-transparent hover:border-slate-100">
                     <div className="flex items-center gap-3">
                       <span className="text-sm text-slate-400 font-medium">{12 + (i*9)}.</span>
                       <div className="flex items-center gap-2">
                         <div className={cn("w-6 h-6 rounded flex items-center justify-center bg-white shadow-sm border border-slate-100", s.color)}>
                           <s.icon className="w-3.5 h-3.5" />
                         </div>
                         <span className="text-sm font-semibold text-slate-700">{s.title}</span>
                       </div>
                     </div>
                     <span className="text-sm font-bold text-slate-800 flex items-center gap-1">{s.count} <ChevronDown className="w-3 h-3 text-slate-300"/></span>
                   </div>
                 ))}
