            <DashboardTabs 
              tabs={['Fleet Analytics', 'Driver Insights', 'Recent Activity']} 
              activeTab={analyticsTab} 
              onTabSelect={setAnalyticsTab} 
            />
            <div className="flex items-center gap-3">
              <button className="flex items-center gap-2 px-3 py-1.5 bg-white border border-slate-200 rounded-md text-sm font-medium text-slate-600 hover:bg-slate-50 shadow-sm">
