                </ResponsiveContainer>
              </div>
            </SectionCard>

            {/* Fleet Composition */}
            <SectionCard>
              <div className="flex items-start justify-between mb-2">
                <div>
                  <h3 className="text-base font-semibold text-slate-800">Fleet Composition by Vehicle Type</h3>
