                <button className="text-slate-400 flex items-center gap-1 text-xs px-2 py-1 bg-white border border-slate-200 rounded shadow-sm hover:bg-slate-50">
                  Daily <ChevronDown className="w-3 h-3" />
                </button>
              </div>
              <div className="h-[220px] w-full pt-4">
                <ResponsiveContainer width="100%" height="100%">
                  <BarChart data={FLEET_COMP_DATA} layout="vertical" margin={{ top: 0, right: 30, left: 30, bottom: 0 }} barSize={12}>
